const body = $input.first().json.body || {};

const registros = [];

// ── 1. MENSAGENS INBOUND (enviadas pelo paciente) ──────────────
if (body.messages && Array.isArray(body.messages)) {
  const contacts = body.contacts || [];

  for (const msg of body.messages) {
    const wa_id = msg.from || '';

    // Busca nome do contato
    const contato = contacts.find(c => c.wa_id === wa_id) || {};
    const contact_name = contato.profile?.name || null;

    // Extrai conteúdo baseado no tipo
    let content = null;
    const tipo = msg.type || 'text';

    if (tipo === 'text') {
      content = msg.text?.body || null;
    } else if (tipo === 'image') {
      content = msg.image?.caption || msg.image?.id || null;
    } else if (tipo === 'audio') {
      content = msg.audio?.id || null;
    } else if (tipo === 'video') {
      content = msg.video?.caption || msg.video?.id || null;
    } else if (tipo === 'document') {
      content = msg.document?.caption || msg.document?.filename || msg.document?.id || null;
    } else if (tipo === 'sticker') {
      content = msg.sticker?.id || null;
    } else if (tipo === 'location') {
      content = `${msg.location?.latitude},${msg.location?.longitude}` || null;
    } else if (tipo === 'button') {
      content = msg.button?.text || null;
    } else if (tipo === 'interactive') {
      content = msg.interactive?.button_reply?.title ||
                msg.interactive?.list_reply?.title ||
                JSON.stringify(msg.interactive) || null;
    } else {
      content = JSON.stringify(msg);
    }

    // Converte timestamp Unix → ISO
    let timestamp = null;
    if (msg.timestamp) {
      timestamp = new Date(parseInt(msg.timestamp) * 1000).toISOString();
    }

    registros.push({
      message_id: msg.id || null,
      wa_id,
      contact_name,
      direction: 'inbound',
      type: tipo,
      content,
      status: null,
      timestamp,
      raw: msg
    });
  }
}

// ── 2. STATUS UPDATES (confirmações de entrega das nossas msgs) ─
if (body.statuses && Array.isArray(body.statuses)) {
  for (const st of body.statuses) {
    const timestamp = st.timestamp
      ? new Date(parseInt(st.timestamp) * 1000).toISOString()
      : null;

    registros.push({
      message_id: st.id || null,
      wa_id: st.recipient_id || '',
      contact_name: null,
      direction: 'outbound',
      type: 'status_update',
      content: null,
      status: st.status || null,
      timestamp,
      raw: st
    });
  }
}

// Se não há nada para processar, retorna lista vazia
if (registros.length === 0) {
  return [{ json: { nada_para_salvar: true } }];
}

return registros.map(r => ({ json: r }));

const statusCode = $json.statusCode;
console.log(`[Turn.io Webhook] Mensagem salva no Supabase. Status: ${statusCode}`);
return [{ json: { ok: true, statusCode } }];

const statusCode = $json.statusCode;
const body = $json.body;
console.error(`[Turn.io Webhook] ERRO ao salvar no Supabase. Status: ${statusCode}`, JSON.stringify(body));
return [{ json: { ok: false, statusCode, erro: body } }];
